import{c as i,S as h,j as l,m as a}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Quản lý lớp học","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/quan-ly-lop-hoc.md","filePath":"giao-vien/quan-ly-lop-hoc.md","lastUpdated":0}'),o={name:"giao-vien/quan-ly-lop-hoc.md"};function t(c,n,r,e,g,p){return h(),l("div",null,[...n[0]||(n[0]=[a('<h1 id="quan-ly-lop-hoc" tabindex="-1">Quản lý lớp học <a class="header-anchor" href="#quan-ly-lop-hoc" aria-label="Permalink to “Quản lý lớp học”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/class-management/:courseId</code></p><p>Lớp học là <strong>một nhóm học viên cùng học một khóa theo lịch / mục tiêu chung</strong>. Khác với khóa học (nội dung), lớp học là một đơn vị <strong>vận hành</strong> (lịch, danh sách, điểm danh, chấm điểm theo lớp).</p><h2 id="khi-nao-nen-dung-lop-hoc" tabindex="-1">Khi nào nên dùng lớp học? <a class="header-anchor" href="#khi-nao-nen-dung-lop-hoc" aria-label="Permalink to “Khi nào nên dùng lớp học?”">​</a></h2><ul><li>Trung tâm offline chuyển lên online, muốn quản lý theo lớp như cũ.</li><li>Tổ chức <strong>lớp ôn thi cấp tốc</strong> trong 2-3 tháng.</li><li>Cần <strong>so sánh điểm giữa các học viên trong cùng nhóm</strong>.</li><li>Có <strong>lịch live stream</strong> đi kèm khóa học video.</li></ul><h2 id="truy-cap" tabindex="-1">Truy cập <a class="header-anchor" href="#truy-cap" aria-label="Permalink to “Truy cập”">​</a></h2><p>Từ chi tiết khóa học (<code>https://lamsonedutech.vn/teacher/detail-course/:idCourse</code>) → tab <strong>Lớp học</strong> → chọn / tạo lớp.</p><h2 id="tao-lop-moi" tabindex="-1">Tạo lớp mới <a class="header-anchor" href="#tao-lop-moi" aria-label="Permalink to “Tạo lớp mới”">​</a></h2><ol><li>Bấm <strong>Thêm lớp</strong>.</li><li>Điền: <ul><li><strong>Tên lớp</strong> (vd: &quot;Lớp HSA-K12 Đợt 1 - 2026&quot;)</li><li><strong>Khóa học áp dụng</strong> (mặc định = khóa hiện tại)</li><li><strong>Ngày bắt đầu - Ngày kết thúc</strong></li><li><strong>Số lượng học viên tối đa</strong> (vd: 30)</li><li><strong>Mô tả</strong> (lịch học, yêu cầu)</li><li>(Tùy chọn) <strong>Lịch live</strong>: ngày trong tuần + giờ + link buổi học</li></ul></li><li>Lưu.</li></ol><h2 id="them-hoc-vien-vao-lop" tabindex="-1">Thêm học viên vào lớp <a class="header-anchor" href="#them-hoc-vien-vao-lop" aria-label="Permalink to “Thêm học viên vào lớp”">​</a></h2><h3 id="cach-1-moi-bang-sđt-email" tabindex="-1">Cách 1: Mời bằng SĐT / Email <a class="header-anchor" href="#cach-1-moi-bang-sđt-email" aria-label="Permalink to “Cách 1: Mời bằng SĐT / Email”">​</a></h3><ol><li>Vào chi tiết lớp → <strong>Thêm học viên</strong>.</li><li>Nhập danh sách SĐT (mỗi dòng 1 số).</li><li>Hệ thống tự khớp với tài khoản học viên có sẵn → gửi lời mời.</li><li>Học viên xác nhận tham gia → vào lớp.</li></ol><h3 id="cach-2-hoc-vien-tu-xin-vao-lop" tabindex="-1">Cách 2: Học viên tự xin vào lớp <a class="header-anchor" href="#cach-2-hoc-vien-tu-xin-vao-lop" aria-label="Permalink to “Cách 2: Học viên tự xin vào lớp”">​</a></h3><ul><li>Lớp được hiển thị trong trang khóa (nếu cấu hình <strong>Cho phép học viên tự xin</strong>).</li><li>Học viên bấm <strong>Xin vào lớp</strong> → giáo viên duyệt.</li></ul><h3 id="cach-3-import-excel" tabindex="-1">Cách 3: Import Excel <a class="header-anchor" href="#cach-3-import-excel" aria-label="Permalink to “Cách 3: Import Excel”">​</a></h3><ul><li>Tải template Excel → điền SĐT / Email → upload lại.</li></ul><h2 id="quan-ly-thanh-vien-lop" tabindex="-1">Quản lý thành viên lớp <a class="header-anchor" href="#quan-ly-thanh-vien-lop" aria-label="Permalink to “Quản lý thành viên lớp”">​</a></h2><p>Tab <strong>Học viên</strong> trong chi tiết lớp:</p><ul><li>Danh sách học viên đang trong lớp.</li><li><strong>Trạng thái</strong>: Đang học / Tạm nghỉ / Đã loại.</li><li>Tiến độ học (%), điểm trung bình của các bài kiểm tra trong lớp.</li><li>Có thể <strong>loại học viên khỏi lớp</strong> (không phải xóa tài khoản học viên).</li></ul><h2 id="lich-hoc-buoi-hoc" tabindex="-1">Lịch học / Buổi học <a class="header-anchor" href="#lich-hoc-buoi-hoc" aria-label="Permalink to “Lịch học / Buổi học”">​</a></h2><p>Tab <strong>Lịch học</strong>:</p><ul><li>Lịch trình các buổi học live / offline.</li><li>Mỗi buổi có: chủ đề, giờ, link join (Zoom / Google Meet).</li><li>Học viên thấy lịch trong khóa của họ.</li></ul><h3 id="tao-buoi-hoc" tabindex="-1">Tạo buổi học <a class="header-anchor" href="#tao-buoi-hoc" aria-label="Permalink to “Tạo buổi học”">​</a></h3><ol><li>Bấm <strong>Thêm buổi học</strong>.</li><li>Điền: ngày, giờ, chủ đề, link join, link tài liệu.</li><li>Lưu → hệ thống thông báo cho học viên trong lớp.</li></ol><h2 id="điem-danh" tabindex="-1">Điểm danh <a class="header-anchor" href="#điem-danh" aria-label="Permalink to “Điểm danh”">​</a></h2><p>Sau mỗi buổi học live, vào <strong>Điểm danh</strong>:</p><ul><li>Tick từng học viên có mặt / vắng / muộn.</li><li>Có thể tự động: bật <strong>Điểm danh tự động qua link join</strong> (nếu hệ thống tích hợp).</li><li>Xuất báo cáo điểm danh theo tuần / tháng.</li></ul><h2 id="bai-tap-theo-lop" tabindex="-1">Bài tập theo lớp <a class="header-anchor" href="#bai-tap-theo-lop" aria-label="Permalink to “Bài tập theo lớp”">​</a></h2><p>Tab <strong>Bài tập</strong>:</p><ul><li>Giao bài tập riêng cho lớp (deadline cụ thể).</li><li>Khác với bài luyện tập trong khóa (mở rộng cho mọi học viên), bài tập lớp <strong>chỉ học viên trong lớp</strong> thấy.</li><li>Có thể chấm thủ công + nhận xét.</li></ul><h2 id="thong-bao-lop" tabindex="-1">Thông báo lớp <a class="header-anchor" href="#thong-bao-lop" aria-label="Permalink to “Thông báo lớp”">​</a></h2><ul><li>Gửi thông báo cho cả lớp: lịch nghỉ, đổi giờ, lời nhắc trước buổi học.</li><li>Học viên nhận qua email / push notification.</li></ul><h2 id="bao-cao-lop" tabindex="-1">Báo cáo lớp <a class="header-anchor" href="#bao-cao-lop" aria-label="Permalink to “Báo cáo lớp”">​</a></h2><p>Tab <strong>Thống kê</strong>:</p><ul><li>Tỷ lệ điểm danh từng học viên.</li><li>Điểm trung bình từng bài kiểm tra so với điểm trung bình lớp.</li><li>Xếp hạng trong lớp.</li><li>Học viên cần hỗ trợ (điểm thấp / vắng nhiều).</li></ul><h2 id="đong-lop" tabindex="-1">Đóng lớp <a class="header-anchor" href="#đong-lop" aria-label="Permalink to “Đóng lớp”">​</a></h2><p>Khi lớp kết thúc:</p><ol><li>Vào chi tiết lớp → <strong>Kết thúc lớp</strong>.</li><li>Hệ thống sinh <strong>báo cáo tổng kết</strong> (PDF) - có thể gửi từng học viên/phụ huynh.</li><li>Lớp ở trạng thái <strong>Đã đóng</strong> - lịch sử vẫn xem được.</li></ol><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên ngoài lớp nhưng vẫn vào học khóa được không?</strong> → Có. Lớp là <strong>thêm</strong> trên khóa, không thay thế. Học viên đã mua khóa luôn vào học được, lớp chỉ thêm cấu trúc quản lý.</p><p><strong>Tôi muốn xóa toàn bộ học viên khỏi lớp.</strong> → Bấm <strong>... → Loại tất cả</strong>. Cẩn trọng, không khôi phục được.</p><p><strong>Học viên báo &quot;không thấy lớp trong tài khoản&quot;.</strong> → Kiểm tra: học viên đã chấp nhận lời mời chưa? Lớp đã active chưa? Khóa của lớp có còn quyền truy cập?</p>',42)])])}const m=i(o,[["render",t]]);export{u as __pageData,m as default};
